class Solution:
    def minimumSubstringsInPartition(self, s: str) -> int:
        n = len(s)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            freq = {}
            for j in range(i - 1, -1, -1):
                c = s[j]
                freq[c] = freq.get(c, 0) + 1
                if all(v == freq[c] for v in freq.values()):
                    dp[i] = min(dp[i], dp[j] + 1)
        return dp[n]
